import ldap

def search_user_by_username(ldap_url, base_dn, bind_dn, bind_password, username):
    # Connect to the LDAP server
    l = ldap.initialize(ldap_url)
    l.set_option(ldap.OPT_REFERRALS, 0)
    l.simple_bind_s(bind_dn, bind_password)

    # Define the search filter and attributes
    search_filter = f"uid={username}"
    search_attributes = ['cn', 'mail', 'uid']

    # Perform the search
    result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, search_attributes)
    results = []
    while 1:
        type_, data = l.result(result_id, 0)
        if not data:
            break
        results.append(data)

    # Close the connection
    l.unbind_s()

    return results

